// ============================================
// ISW CERTENT EQUITY MANAGEMENT ICP DATA PRE-PROCESSOR v2
// Adds Gong Calls intelligence layer
// ============================================

const allItems = $input.all().map(item => item.json);

// Separate CRM and Gong data by _source label
const crmItems = allItems.filter(i => i._source === 'crm');
const gongAll  = allItems.filter(i => i._source === 'gong');

// Filter Gong to Certent EM product line only
const gongItems = gongAll.filter(i => {
  const pl = (i['Product Line'] || '').toLowerCase();
  return pl.includes('equity management') || pl.includes('certent equity');
});

console.log('CRM items: ' + crmItems.length +
  ', Gong (all): ' + gongAll.length +
  ', Gong (CEM): ' + gongItems.length);

// ============================================
// STEP 1: FILTER WON / LOST (CRM)
// ============================================

const wonDataRaw  = crmItems.filter(item => (item['Opportunity.Stage Name'] || '').trim() === 'Closed Won');
const lostDataRaw = crmItems.filter(item => (item['Opportunity.Stage Name'] || '').trim() === 'Closed Lost');

console.log('Raw CRM: ' + crmItems.length + ' total, ' + wonDataRaw.length + ' Won, ' + lostDataRaw.length + ' Lost');

// ============================================
// STEP 2: AMENDMENT EXCLUSION
// ============================================

const isAmendment = (row) => (row['Opportunity.Record_Type_Name_C'] || '').trim() === 'Amendment';

const wonData    = wonDataRaw.filter(r  => !isAmendment(r));
const lostData   = lostDataRaw.filter(r => !isAmendment(r));
const amendExWon  = wonDataRaw.length  - wonData.length;
const amendExLost = lostDataRaw.length - lostData.length;

console.log('Amendments excluded: Won -' + amendExWon + ', Lost -' + amendExLost);

// ============================================
// HELPERS
// ============================================

const sum        = arr => arr.reduce((a, b) => a + b, 0);
const pct        = (num, denom) => denom ? ((num / denom) * 100).toFixed(1) : '0.0';
const currencyK  = num => {
  const val = num || 0;
  if (val >= 1000000) return '$' + (val / 1000000).toFixed(1) + 'm';
  if (val >= 1000)    return '$' + (val / 1000).toFixed(1) + 'k';
  return '$' + Math.round(val).toLocaleString();
};
const safeStr    = val => (val || '').toString().trim();
const avgNonZero = arr => {
  const valid = arr.filter(v => v !== null && v !== undefined && v > 0);
  return valid.length ? valid.reduce((a, b) => a + b, 0) / valid.length : null;
};

// Parse ARR: "USD 24,203.64" -> number
const parseARR = (val) => {
  if (!val) return 0;
  const cleaned = val.toString().replace(/^USD\s*/i, '').replace(/,/g, '');
  const n = parseFloat(cleaned);
  return isNaN(n) ? 0 : n;
};

// ============================================
// CLASSIFICATION FUNCTIONS
// ============================================

const getFTEBand = (row) => {
  const size = safeStr(row['Size']).toLowerCase();
  if (size.match(/^1 emp/) || size.includes('2-10') || size.includes('1-10')) return '1-10 FTEs';
  if (size.includes('11-50'))  return '11-50 FTEs';
  if (size.includes('51-200')) return '51-200 FTEs';
  if (size.includes('201-500')) return '201-500 FTEs';
  if (size.includes('501') || size.includes('1,001') || size.includes('5,001') || size.includes('10,001')) return '500+ FTEs';
  const emp = parseInt(row['Number Of Employees']) || 0;
  if (emp === 0)   return 'Unknown';
  if (emp <= 10)   return '1-10 FTEs';
  if (emp <= 50)   return '11-50 FTEs';
  if (emp <= 200)  return '51-200 FTEs';
  if (emp <= 500)  return '201-500 FTEs';
  return '500+ FTEs';
};

const getUSState       = (row) => { const s = safeStr(row['State']); return s.length >= 2 ? s : 'Unknown'; };
const getCountry       = (row) => safeStr(row['Country']) || 'Unknown';
const getIndustry      = (row) => {
  const ind2 = safeStr(row['Industry (2)']);
  if (ind2.length > 2) return ind2;
  const ind1 = safeStr(row['Industry']);
  return ind1.length > 2 ? (ind1.length > 50 ? ind1.substring(0, 50) : ind1) : 'Unknown';
};
const getOwnershipType = (row) => {
  const ct = safeStr(row['Company Type']).toLowerCase();
  if (ct.includes('public'))    return 'Public';
  if (ct.includes('privately') || ct === 'private') return 'Private';
  if (ct.includes('partnership')) return 'Partnership';
  if (ct.includes('nonprofit') || ct.includes('non-profit')) return 'Nonprofit';
  if (ct.includes('government')) return 'Government';
  return ct.length > 1 ? safeStr(row['Company Type']) : 'Unknown';
};
const getCustomerType  = (row) => {
  const type = safeStr(row['Type']);
  return (type === 'New Customer' || type === 'Existing Customer') ? type : 'Unknown';
};
const getRevenueBand   = (row) => safeStr(row['Annual Revenue']) || 'Unknown';

// ============================================
// OVERALL AVERAGES (for ICP Scoring)
// ============================================

const overallCvR     = (wonData.length / (wonData.length + lostData.length)) * 100;
const overallARRVals = wonData.map(r => parseARR(r['Opportunity.Annualized_Bookings_Conversion_C.CONVERT'])).filter(v => v > 0);
const overallAvgARR  = avgNonZero(overallARRVals) || 0;

console.log('Overall CvR: ' + overallCvR.toFixed(1) + '%, Overall Avg ARR: ' + currencyK(overallAvgARR));

// ============================================
// SEGMENT METRICS CALCULATOR
// ============================================

const calculateSegmentMetrics = (wonInSeg, lostInSeg, segName) => {
  const totalOpps = wonInSeg.length + lostInSeg.length;
  const wonCount  = wonInSeg.length;
  const cvr       = totalOpps > 0 ? (wonCount / totalOpps) * 100 : 0;
  const arrVals   = wonInSeg.map(r => parseARR(r['Opportunity.Annualized_Bookings_Conversion_C.CONVERT'])).filter(v => v > 0);
  const totalARR  = sum(arrVals);
  const avgARR    = avgNonZero(arrVals);
  const weightedVal = avgARR ? (cvr / 100) * avgARR : 0;
  const cvrNorm   = overallCvR > 0 ? (cvr / overallCvR) : 1;
  const arrNorm   = overallAvgARR > 0 && avgARR ? (avgARR / overallAvgARR) : 1;
  const icpScoreRaw = (0.6 * cvrNorm) + (0.4 * arrNorm);
  const icpIndex    = Math.round(icpScoreRaw * 100);
  let icpScore = 'NEUTRAL', icpSymbol = '--';
  if (icpScoreRaw > 1.10) { icpScore = 'PRIORITISE';   icpSymbol = '^'; }
  else if (icpScoreRaw < 0.90) { icpScore = 'DEPRIORITISE'; icpSymbol = 'v'; }
  return {
    segment: segName, totalOpps, wonCount,
    cvr: cvr.toFixed(1) + '%', cvrRaw: cvr,
    totalARR: currencyK(totalARR),
    avgARR: avgARR ? currencyK(avgARR) : 'N/A', avgARRRaw: avgARR || 0,
    weightedValue: currencyK(weightedVal),
    icpScore, icpSymbol, icpScoreRaw, icpIndex
  };
};

// Table generator (with Index column)
const generateTable = (rows, title) => {
  let t = '| ' + title + ' | Total Opps | Won # | CvR | Total ARR | Avg ARR | CvR x Avg ARR | Index | ICP Score |\n';
  t += '|---|---|---|---|---|---|---|---|---|\n';
  rows.forEach(r => {
    t += '| ' + r.segment + ' | ' + r.totalOpps + ' | ' + r.wonCount + ' | ' + r.cvr + ' | ' + r.totalARR + ' | ' + r.avgARR + ' | ' + r.weightedValue + ' | ' + r.icpIndex + ' | ' + r.icpSymbol + ' ' + r.icpScore + ' |\n';
  });
  return t;
};

// Group small segments into "Other"
const groupSmall = (metricsArr, threshold, wonD, lostD, classifyFn) => {
  const large = metricsArr.filter(m => m.totalOpps >= threshold);
  const small = metricsArr.filter(m => m.totalOpps > 0 && m.totalOpps < threshold);
  if (!small.length) return { segments: large, otherNote: '' };
  const oWon = [], oLost = [], names = [];
  small.forEach(seg => {
    names.push(seg.segment + ' (' + seg.totalOpps + ')');
    wonD.forEach(r  => { if (classifyFn(r) === seg.segment) oWon.push(r); });
    lostD.forEach(r => { if (classifyFn(r) === seg.segment) oLost.push(r); });
  });
  if (oWon.length + oLost.length > 0) large.push(calculateSegmentMetrics(oWon, oLost, 'Other'));
  return { segments: large, otherNote: '*"Other" includes ' + small.length + ' segments with <' + threshold + ' opportunities: ' + names.join(', ') + '*' };
};

// ============================================
// DATASET OVERVIEW
// ============================================

const totalDataset = crmItems.length;
const totalWon     = wonData.length;
const totalLost    = lostData.length;
const totalRecords = totalWon + totalLost;

const allARR     = wonData.map(r => parseARR(r['Opportunity.Annualized_Bookings_Conversion_C.CONVERT'])).filter(v => v > 0);
const totalARRAll = sum(allARR);
const avgARRAll   = avgNonZero(allARR) || 0;

const enrichRate = (field, minLen = 2) => pct(wonData.filter(r => safeStr(r[field]).length > minLen).length, totalWon);

// ============================================
// PAGE: FTE BAND ANALYSIS
// ============================================

const FTE_MIN     = 5;
const fteBands    = ['1-10 FTEs', '11-50 FTEs', '51-200 FTEs', '201-500 FTEs', '500+ FTEs'];
const fteMetricsAll = fteBands.map(b => calculateSegmentMetrics(
  wonData.filter(r  => getFTEBand(r) === b),
  lostData.filter(r => getFTEBand(r) === b), b
)).filter(m => m.totalOpps > 0);
const fteGrouped  = groupSmall(fteMetricsAll, FTE_MIN, wonData, lostData, getFTEBand);
const fteMetrics  = [...fteGrouped.segments, calculateSegmentMetrics(wonData, lostData, '**TOTAL**')];
const fteTable    = generateTable(fteMetrics, 'FTE Band');
const fteData     = fteMetrics.filter(m => !['**TOTAL**', 'Other'].includes(m.segment));
const topFTEByCvR  = [...fteData].sort((a, b) => b.cvrRaw    - a.cvrRaw)[0];
const topFTEByARR  = [...fteData].sort((a, b) => b.avgARRRaw - a.avgARRRaw)[0];
const topFTEByVol  = [...fteData].sort((a, b) => b.wonCount  - a.wonCount)[0];
const prioritisedFTE    = fteData.filter(m => m.icpScore === 'PRIORITISE').map(m => m.segment).join(', ')   || 'None';
const deprioritisedFTE  = fteData.filter(m => m.icpScore === 'DEPRIORITISE').map(m => m.segment).join(', ') || 'None';

// ============================================
// PAGE: GEOGRAPHY ANALYSIS
// ============================================

const stateMap = {};
[...wonData, ...lostData].forEach(row => {
  const country = safeStr(row['Country']).toLowerCase();
  if (!['united states', 'us', 'usa'].includes(country)) return;
  const state = getUSState(row);
  if (!state || state === 'Unknown') return;
  if (!stateMap[state]) stateMap[state] = { won: [], lost: [] };
  if (safeStr(row['Opportunity.Stage Name']) === 'Closed Won') stateMap[state].won.push(row);
  else stateMap[state].lost.push(row);
});

const GEO_MIN = 3;
const stateMetricsAll = Object.entries(stateMap)
  .map(([s, d]) => calculateSegmentMetrics(d.won, d.lost, s))
  .sort((a, b) => b.wonCount - a.wonCount);
const stateGrouped = groupSmall(stateMetricsAll, GEO_MIN, wonData, lostData, r => {
  const c = safeStr(r['Country']).toLowerCase();
  if (!['united states', 'us', 'usa'].includes(c)) return null;
  return getUSState(r);
});

const usWon  = wonData.filter(r  => ['united states', 'us', 'usa'].includes(safeStr(r['Country']).toLowerCase()));
const usLost = lostData.filter(r => ['united states', 'us', 'usa'].includes(safeStr(r['Country']).toLowerCase()));
const stateMetrics = [
  ...stateGrouped.segments.sort((a, b) => {
    if (a.segment === 'Other') return 1;
    if (b.segment === 'Other') return -1;
    return b.wonCount - a.wonCount;
  }),
  calculateSegmentMetrics(usWon, usLost, '**US TOTAL**')
];
const stateTable       = generateTable(stateMetrics, 'US State');
const prioritisedState   = stateMetrics.filter(m => m.icpScore === 'PRIORITISE'   && !['**US TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';
const deprioritisedState = stateMetrics.filter(m => m.icpScore === 'DEPRIORITISE' && !['**US TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';

const countryMapData = {};
[...wonData, ...lostData].forEach(row => {
  const c = getCountry(row);
  if (!c || c === 'Unknown') return;
  if (!countryMapData[c]) countryMapData[c] = { won: [], lost: [] };
  if (safeStr(row['Opportunity.Stage Name']) === 'Closed Won') countryMapData[c].won.push(row);
  else countryMapData[c].lost.push(row);
});
const countryMetrics = [
  ...Object.entries(countryMapData)
    .map(([c, d]) => calculateSegmentMetrics(d.won, d.lost, c))
    .sort((a, b) => b.wonCount - a.wonCount).slice(0, 15),
  calculateSegmentMetrics(wonData, lostData, '**TOTAL**')
];
const countryTable = generateTable(countryMetrics, 'Country');

// ============================================
// PAGE: INDUSTRY ANALYSIS
// ============================================

const IND_MIN = 5;
const indMap  = {};
[...wonData, ...lostData].forEach(row => {
  const ind = getIndustry(row);
  if (ind === 'Unknown') return;
  if (!indMap[ind]) indMap[ind] = { won: [], lost: [] };
  if (safeStr(row['Opportunity.Stage Name']) === 'Closed Won') indMap[ind].won.push(row);
  else indMap[ind].lost.push(row);
});
const indMetricsAll = Object.entries(indMap)
  .map(([i, d]) => calculateSegmentMetrics(d.won, d.lost, i))
  .sort((a, b) => b.wonCount - a.wonCount);
const largeInd = indMetricsAll.filter(m => m.totalOpps >= IND_MIN).slice(0, 20);
const smallInd = indMetricsAll.filter(m => m.totalOpps > 0 && m.totalOpps < IND_MIN);
let indOtherNote = '';
if (smallInd.length) {
  const oW = [], oL = [];
  smallInd.forEach(s => { if (indMap[s.segment]) { oW.push(...indMap[s.segment].won); oL.push(...indMap[s.segment].lost); } });
  if (oW.length + oL.length > 0) largeInd.push(calculateSegmentMetrics(oW, oL, 'Other'));
  indOtherNote = '*"Other" includes ' + smallInd.length + ' industries with <' + IND_MIN + ' opportunities each*';
}
const knownIndWon  = wonData.filter(r  => getIndustry(r) !== 'Unknown');
const knownIndLost = lostData.filter(r => getIndustry(r) !== 'Unknown');
largeInd.push(calculateSegmentMetrics(knownIndWon, knownIndLost, '**TOTAL**'));
const indTable          = generateTable(largeInd, 'Industry');
const prioritisedInd    = largeInd.filter(m => m.icpScore === 'PRIORITISE'   && !['**TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';
const deprioritisedInd  = largeInd.filter(m => m.icpScore === 'DEPRIORITISE' && !['**TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';

// ============================================
// PAGE: COMPANY TYPE ANALYSIS
// ============================================

const OWN_MIN  = 5;
const ownTypes = ['Public', 'Private', 'Partnership', 'Nonprofit', 'Government'];
const ownMetricsAll = ownTypes.map(t => calculateSegmentMetrics(
  wonData.filter(r  => getOwnershipType(r) === t),
  lostData.filter(r => getOwnershipType(r) === t), t
)).filter(m => m.totalOpps > 0);
const ownGrouped = groupSmall(ownMetricsAll, OWN_MIN, wonData, lostData, getOwnershipType);
const ownMetrics = [
  ...ownGrouped.segments.sort((a, b) => {
    if (a.segment === 'Other') return 1; if (b.segment === 'Other') return -1;
    return b.wonCount - a.wonCount;
  }),
  calculateSegmentMetrics(wonData, lostData, '**TOTAL**')
];
const ownTable          = generateTable(ownMetrics, 'Company Type');
const prioritisedOwn    = ownMetrics.filter(m => m.icpScore === 'PRIORITISE'   && !['**TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';
const deprioritisedOwn  = ownMetrics.filter(m => m.icpScore === 'DEPRIORITISE' && !['**TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';

// ============================================
// PAGE: CUSTOMER TYPE ANALYSIS
// ============================================

const custTypes = ['New Customer', 'Existing Customer'];
const custMetrics = custTypes.map(t => calculateSegmentMetrics(
  wonData.filter(r  => getCustomerType(r) === t),
  lostData.filter(r => getCustomerType(r) === t), t
)).filter(m => m.totalOpps > 0);
const unkCustWon  = wonData.filter(r  => getCustomerType(r) === 'Unknown');
const unkCustLost = lostData.filter(r => getCustomerType(r) === 'Unknown');
if (unkCustWon.length + unkCustLost.length > 0) custMetrics.push(calculateSegmentMetrics(unkCustWon, unkCustLost, 'Unknown'));
custMetrics.push(calculateSegmentMetrics(wonData, lostData, '**TOTAL**'));
const custTable = generateTable(custMetrics, 'Customer Type');

// ============================================
// PAGE: ANNUAL REVENUE BAND ANALYSIS
// ============================================

const REV_MIN     = 3;
const revMapData  = {};
[...wonData, ...lostData].forEach(row => {
  const rev = getRevenueBand(row);
  if (!rev || rev === 'Unknown' || rev === '') return;
  if (!revMapData[rev]) revMapData[rev] = { won: [], lost: [] };
  if (safeStr(row['Opportunity.Stage Name']) === 'Closed Won') revMapData[rev].won.push(row);
  else revMapData[rev].lost.push(row);
});
const revOrder = ['Less Than 1M', '1M-5M', '5M-10M', '10M-25M', '25M-50M', '50M-75M', '75M-200M', '200M-1B', '1B-10B', '10B+'];
const revMetricsAll = Object.entries(revMapData)
  .map(([r, d]) => calculateSegmentMetrics(d.won, d.lost, r))
  .sort((a, b) => {
    const ai = revOrder.indexOf(a.segment), bi = revOrder.indexOf(b.segment);
    if (ai === -1 && bi === -1) return b.wonCount - a.wonCount;
    if (ai === -1) return 1; if (bi === -1) return -1; return ai - bi;
  });
const revGrouped    = groupSmall(revMetricsAll, REV_MIN, wonData, lostData, getRevenueBand);
const knownRevWon   = wonData.filter(r  => getRevenueBand(r) !== 'Unknown' && getRevenueBand(r) !== '');
const knownRevLost  = lostData.filter(r => getRevenueBand(r) !== 'Unknown' && getRevenueBand(r) !== '');
const revMetrics    = [...revGrouped.segments, calculateSegmentMetrics(knownRevWon, knownRevLost, '**TOTAL**')];
const revTable          = generateTable(revMetrics, 'Annual Revenue');
const prioritisedRev    = revMetrics.filter(m => m.icpScore === 'PRIORITISE'   && !['**TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';
const deprioritisedRev  = revMetrics.filter(m => m.icpScore === 'DEPRIORITISE' && !['**TOTAL**', 'Other'].includes(m.segment)).map(m => m.segment).join(', ') || 'None';

// ============================================
// PAGE: SALES REP PERFORMANCE
// ============================================

const repMapData2 = {};
[...wonData, ...lostData].forEach(row => {
  const rep = safeStr(row['Opportunity.Owner_Name_C']) || 'Unknown';
  if (!repMapData2[rep]) repMapData2[rep] = { won: [], lost: [] };
  if (safeStr(row['Opportunity.Stage Name']) === 'Closed Won') repMapData2[rep].won.push(row);
  else repMapData2[rep].lost.push(row);
});
const repMetrics = [
  ...Object.entries(repMapData2)
    .map(([r, d]) => calculateSegmentMetrics(d.won, d.lost, r))
    .sort((a, b) => b.wonCount - a.wonCount).slice(0, 15),
  calculateSegmentMetrics(wonData, lostData, '**TOTAL**')
];
const repTable = generateTable(repMetrics, 'Sales Rep');

// ============================================
// GONG CALLS ANALYSIS
// ============================================

// Separate by deal outcome
const gongWonAccts      = gongItems.filter(i => (i['Has Closed Won'] || '').toLowerCase() === 'yes' || (i['Deal Status'] || '') === 'CLOSED_WON');
const gongLostAccts     = gongItems.filter(i => (i['Deal Status'] || '') === 'CLOSED_LOST');
const gongPipelineAccts = gongItems.filter(i => (i['Deal Status'] || '').includes('PIPELINE'));

// Call Outcome distribution
const outcomeMap = {};
gongItems.forEach(i => {
  const o = safeStr(i['Call Outcome']) || 'Unknown';
  outcomeMap[o] = (outcomeMap[o] || 0) + 1;
});

// Call Outcome by win/loss
const wonOutcomeMap = {}, lostOutcomeMap = {};
gongWonAccts.forEach(i  => { const o = safeStr(i['Call Outcome']) || 'Unknown'; wonOutcomeMap[o]  = (wonOutcomeMap[o]  || 0) + 1; });
gongLostAccts.forEach(i => { const o = safeStr(i['Call Outcome']) || 'Unknown'; lostOutcomeMap[o] = (lostOutcomeMap[o] || 0) + 1; });

// Call Type distribution
const callTypeMap = {};
gongItems.forEach(i => {
  const ct = safeStr(i['Call Type']) || 'Unknown';
  callTypeMap[ct] = (callTypeMap[ct] || 0) + 1;
});

// Deal Risk distribution (overall + by win/loss)
const riskMap = {}, wonRiskMap = {}, lostRiskMap = {};
gongItems.forEach(i       => { const r = safeStr(i['Deal Risk']) || 'Unknown'; riskMap[r]     = (riskMap[r]     || 0) + 1; });
gongWonAccts.forEach(i    => { const r = safeStr(i['Deal Risk']) || 'Unknown'; wonRiskMap[r]  = (wonRiskMap[r]  || 0) + 1; });
gongLostAccts.forEach(i   => { const r = safeStr(i['Deal Risk']) || 'Unknown'; lostRiskMap[r] = (lostRiskMap[r] || 0) + 1; });

// Budget Signal
const budgetDiscussed    = gongItems.filter(i => safeStr(i['Budget Signal']) === 'DISCUSSED').length;
const budgetNotMentioned = gongItems.filter(i => safeStr(i['Budget Signal']) === 'NOT_MENTIONED').length;
const budgetWonDiscussed = gongWonAccts.filter(i  => safeStr(i['Budget Signal']) === 'DISCUSSED').length;
const budgetLostDiscussed= gongLostAccts.filter(i => safeStr(i['Budget Signal']) === 'DISCUSSED').length;

// Pain Points by win/loss
const wonPainPoints  = gongWonAccts.map(i  => safeStr(i['pain_points'])).filter(Boolean);
const lostPainPoints = gongLostAccts.map(i => safeStr(i['pain_points'])).filter(Boolean);

// Objections by win/loss
const wonObjections  = gongWonAccts.map(i  => safeStr(i['objections'])).filter(Boolean);
const lostObjections = gongLostAccts.map(i => safeStr(i['objections'])).filter(Boolean);

// Competitor mentions
const competitorMentions = {};
gongItems.forEach(i => {
  const comps = safeStr(i['Competitors']);
  if (!comps) return;
  comps.split(',').forEach(c => {
    const comp = c.trim();
    if (comp && comp !== '' && comp.toLowerCase() !== 'none' && comp.toLowerCase() !== 'n/a') {
      competitorMentions[comp] = (competitorMentions[comp] || 0) + 1;
    }
  });
});
const topCompetitors = Object.entries(competitorMentions)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);

// Competitor by win/loss context
const compWinMap = {}, compLossMap = {};
gongWonAccts.forEach(i => {
  const comps = safeStr(i['Competitors']);
  if (!comps) return;
  comps.split(',').forEach(c => {
    const comp = c.trim();
    if (comp && comp !== '') compWinMap[comp] = (compWinMap[comp] || 0) + 1;
  });
});
gongLostAccts.forEach(i => {
  const comps = safeStr(i['Competitors']);
  if (!comps) return;
  comps.split(',').forEach(c => {
    const comp = c.trim();
    if (comp && comp !== '') compLossMap[comp] = (compLossMap[comp] || 0) + 1;
  });
});

// ICP classification from Gong
const icpClassMap = {};
gongItems.forEach(i => {
  const icp = safeStr(i['ICP']) || 'Unknown';
  icpClassMap[icp] = (icpClassMap[icp] || 0) + 1;
});

// Rep performance from Gong
const gongRepMap = {};
gongItems.forEach(i => {
  const rep = safeStr(i['ISW Rep Names']) || 'Unknown';
  if (rep === 'Unknown' || rep === '') return;
